/* eslint-disable no-console */
// PTY session registry — owns all terminal session lifecycle in the main process.
// Sessions survive React component mount/unmount and are identified by a
// main-process-generated sessionId.

"use strict";

/** @typedef {'active'|'exited'|'killed'} SessionStatus */

/**
 * @typedef {Object} SessionEntry
 * @property {string}        sessionId      - Unique ID generated by main process
 * @property {import('node-pty').IPty} ptyProcess - node-pty instance
 * @property {number}        webContentsId  - Owning webContents ID
 * @property {string}        shell          - Shell executable path
 * @property {string}        cwd            - Working directory at spawn time
 * @property {SessionStatus} status         - Current lifecycle status
 * @property {number|null}   exitCode       - Exit code when status is 'exited'
 * @property {number}        createdAt      - Unix timestamp (ms)
 * @property {string}        outputBuffer   - Raw concatenated PTY output, capped at OUTPUT_BUFFER_BYTES
 */

const MAX_SESSIONS_PER_WINDOW = 10;
const MAX_SESSIONS_GLOBAL = 20;
/** Maximum byte size of the raw output buffer retained per session (~200 KB). */
const OUTPUT_BUFFER_BYTES = 200 * 1024;

/** @type {Map<string, SessionEntry>} */
const registry = new Map();

/** Monotonically increasing counter for session IDs */
let sessionCounter = 0;

/**
 * Generate a unique session ID.
 * @returns {string}
 */
function generateSessionId() {
  sessionCounter += 1;
  return `term-${sessionCounter}-${Date.now()}`;
}

/**
 * Count active sessions owned by a specific webContents.
 * @param {number} webContentsId
 * @returns {number}
 */
function countSessionsForWindow(webContentsId) {
  let count = 0;
  for (const entry of registry.values()) {
    if (entry.webContentsId === webContentsId) count += 1;
  }
  return count;
}

/**
 * Append raw PTY data to the output buffer of a session.
 * Trims the oldest bytes from the front when the buffer exceeds OUTPUT_BUFFER_BYTES.
 * Trimming is done on byte boundaries to avoid injecting artificial newlines.
 * @param {SessionEntry} entry
 * @param {string} data - Raw PTY data chunk
 */
function appendToOutputBuffer(entry, data) {
  entry.outputBuffer += data;
  const byteLength = Buffer.byteLength(entry.outputBuffer, "utf8");
  if (byteLength > OUTPUT_BUFFER_BYTES) {
    // Trim from the front by converting to a Buffer and slicing excess bytes
    const buf = Buffer.from(entry.outputBuffer, "utf8");
    entry.outputBuffer = buf.slice(byteLength - OUTPUT_BUFFER_BYTES).toString("utf8");
  }
}

/**
 * Add a new session to the registry.
 * @param {Object} params
 * @param {import('node-pty').IPty} params.ptyProcess
 * @param {number} params.webContentsId
 * @param {string} params.shell
 * @param {string} params.cwd
 * @returns {SessionEntry}
 */
function addSession({ ptyProcess, webContentsId, shell, cwd }) {
  const sessionId = generateSessionId();
  /** @type {SessionEntry} */
  const entry = {
    sessionId,
    ptyProcess,
    webContentsId,
    shell,
    cwd,
    status: "active",
    exitCode: null,
    createdAt: Date.now(),
    outputBuffer: "",
  };
  registry.set(sessionId, entry);
  return entry;
}

/**
 * Retrieve a session by ID, or null if not found.
 * @param {string} sessionId
 * @returns {SessionEntry|null}
 */
function getSession(sessionId) {
  return registry.get(sessionId) ?? null;
}

/**
 * Remove a session from the registry.
 * @param {string} sessionId
 */
function removeSession(sessionId) {
  registry.delete(sessionId);
}

/**
 * Kill a PTY process and mark the session as killed.
 * Idempotent: safe to call on an already-killed session.
 * @param {string} sessionId
 */
function killSession(sessionId) {
  const entry = registry.get(sessionId);
  if (!entry) return;
  if (entry.status !== "active") return;

  entry.status = "killed";
  try {
    entry.ptyProcess.kill();
  } catch (err) {
    console.warn(`[PTY] Error killing session ${sessionId}:`, err);
  }
}

/**
 * Kill all sessions owned by a specific webContents.
 * @param {number} webContentsId
 */
function killSessionsForWindow(webContentsId) {
  for (const entry of registry.values()) {
    if (entry.webContentsId === webContentsId && entry.status === "active") {
      killSession(entry.sessionId);
    }
  }
}

/**
 * Kill all currently active sessions (called on app before-quit).
 */
function killAllSessions() {
  for (const entry of registry.values()) {
    if (entry.status === "active") {
      killSession(entry.sessionId);
    }
  }
}

module.exports = {
  MAX_SESSIONS_PER_WINDOW,
  MAX_SESSIONS_GLOBAL,
  OUTPUT_BUFFER_BYTES,
  registry,
  generateSessionId,
  countSessionsForWindow,
  appendToOutputBuffer,
  addSession,
  getSession,
  removeSession,
  killSession,
  killSessionsForWindow,
  killAllSessions,
};
